import{_ as o,o as t,c as a,a2 as r}from"./chunks/framework.D5wUhsuj.js";const s="/docs/assets/jupyter-spawner-pup-up.Bq_GwZwQ.png",i="/docs/assets/jup-lab-image-selection.BF5V9Yzg.png",n="/docs/assets/jup-lab-examples-repo.D8n9fESJ.png",l="/docs/assets/jup-lab-s3-explorer-wizzard.BsRF-38p.png",f=JSON.parse('{"title":"JupyterLab","description":"","frontmatter":{},"headers":[],"relativePath":"labs/jupyterlab.md","filePath":"labs/jupyterlab.md","lastUpdated":1783546178000}'),d={name:"labs/jupyterlab.md"};function p(c,e,u,h,b,m){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="jupyterlab" tabindex="-1">JupyterLab <a class="header-anchor" href="#jupyterlab" aria-label="Permalink to &quot;JupyterLab&quot;">​</a></h1><p>JupyterLab Labs provide a browser-based Python workspace inside prokube. They are intended for notebooks, data exploration, model development, and quick experiments that should run close to the same storage, compute, and platform services used by production workloads.</p><p>prokube maintains its own JupyterLab images with platform-oriented defaults: common CLI tools, Python packages, S3-compatible object storage integration, image building support, and the public <a href="https://github.com/prokube/examples" target="_blank" rel="noreferrer"><code>prokube/examples</code></a> repository are preconfigured where applicable.</p><div class="info custom-block"><p class="custom-block-title">JupyterLab documentation</p><p>For JupyterLab features that are not specific to prokube, use the upstream <a href="https://jupyterlab.readthedocs.io/" target="_blank" rel="noreferrer">JupyterLab documentation</a>. Administrators who customize notebook images may also want the <a href="https://www.kubeflow.org/docs/components/notebooks/" target="_blank" rel="noreferrer">Kubeflow Notebooks documentation</a>.</p></div><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>Create a JupyterLab Lab from the Labs page. The launch dialog uses the same basic options as other Labs: name, image, compute resources, storage, configurations, and security options.</p><p><img src="'+s+'" alt="Launch JupyterLab" loading="lazy"></p><p>For JupyterLab, the image choice mainly decides which Python and ML stack is available when the Lab starts. Choose an image that matches your workload rather than installing everything manually after startup.</p><p><img src="'+i+'" alt="JupyterLab image selection" loading="lazy"></p><p>Typical image families include:</p><table tabindex="0"><thead><tr><th>Image family</th><th>Use when</th></tr></thead><tbody><tr><td>SciPy</td><td>You need a general-purpose Python data science environment.</td></tr><tr><td>PyTorch</td><td>You develop or inspect PyTorch workloads.</td></tr><tr><td>PyTorch CUDA</td><td>You need PyTorch with GPU support.</td></tr><tr><td>TensorFlow</td><td>You develop or inspect TensorFlow workloads.</td></tr><tr><td>TensorFlow CUDA</td><td>You need TensorFlow with GPU support.</td></tr></tbody></table><p>Use <a href="./custom_notebooks.html">Custom Notebooks</a> if you need a controlled package stack, extra system libraries, or a custom web application instead of one of the standard images.</p><h2 id="what-the-prokube-images-add" tabindex="-1">What the prokube Images Add <a class="header-anchor" href="#what-the-prokube-images-add" aria-label="Permalink to &quot;What the prokube Images Add&quot;">​</a></h2><p>The default JupyterLab images include platform-oriented tooling requested in real user environments.</p><p>Included capabilities depend on the selected image, but the prokube-maintained images commonly include:</p><ul><li>command-line tools such as <code>kubectl</code>, <code>git</code>, <code>tmux</code>, <code>tree</code>, <code>ripgrep</code>, <code>fzf</code>, <code>htop</code>, <code>curl</code>, <code>make</code>, <code>gcc</code>, <code>nvim</code>, and <code>zsh</code>;</li><li>Python tooling and SDKs used across the platform, including the Kubeflow Pipelines SDK, MLflow, <code>s3fs</code>, <code>pyarrow</code>, debugging helpers, and <code>uv</code>;</li><li>S3-compatible object storage access through <code>rclone</code>, with a preconfigured <code>minio</code> remote where available;</li><li>optional S3 browsing in the JupyterLab sidebar for object storage workflows;</li><li>container image build support through Docker CLI and Buildx backed by a remote BuildKit service;</li><li>automatic cloning of the public <a href="https://github.com/prokube/examples" target="_blank" rel="noreferrer"><code>prokube/examples</code></a> repository into the Lab home directory on first start.</li></ul><p>You can also use the JupyterLab terminal for CLI-based coding-agent tools when that fits your workflow, for example the OpenCode CLI, Claude Code, or similar tools. Install additional tools into the persistent home directory rather than the container filesystem; see <a href="./#installing-tools-without-root">Installing Tools Without Root</a>.</p><h2 id="platform-access-from-notebooks" tabindex="-1">Platform Access from Notebooks <a class="header-anchor" href="#platform-access-from-notebooks" aria-label="Permalink to &quot;Platform Access from Notebooks&quot;">​</a></h2><p>A JupyterLab Lab runs inside your workspace as a <a href="https://kubernetes.io/docs/concepts/workloads/pods/" target="_blank" rel="noreferrer">Kubernetes Pod</a>, so it can interact with the platform programmatically. Typical workflows include:</p><ul><li>starting Kubeflow Pipelines with the KFP SDK;</li><li>running hyperparameter tuning or distributed computing experiments;</li><li>reading and writing datasets or model artifacts in S3-compatible object storage;</li><li>building container images for pipeline components or serving runtimes;</li><li>using <code>kubectl</code> to inspect workspace resources when your role allows it;</li><li>working through examples from the cloned <code>prokube/examples</code> repository.</li></ul><p><img src="'+n+'" alt="Examples repository in JupyterLab" loading="lazy"></p><div class="info custom-block"><p class="custom-block-title">Examples repository</p><p>The public <a href="https://github.com/prokube/examples" target="_blank" rel="noreferrer"><code>prokube/examples</code></a> repository contains examples for notebooks, pipelines, serving, MLflow, hyperparameter tuning, RStudio, and related workflows. In the default notebook images it is cloned into the Lab home directory during startup if it is not already present.</p></div><p>JupyterLab uses the same persistence and package-installation model as other Labs. See <a href="./#persistence-and-package-installation">Using Labs</a> for the shared storage rules and <a href="./custom_notebooks.html">Custom Notebooks</a> for repeatable image-based environments.</p><h2 id="object-storage-in-jupyterlab" tabindex="-1">Object Storage in JupyterLab <a class="header-anchor" href="#object-storage-in-jupyterlab" aria-label="Permalink to &quot;Object Storage in JupyterLab&quot;">​</a></h2><p>prokube JupyterLab images can include an S3 browser extension for working with S3-compatible object storage directly from the JupyterLab sidebar.</p><p><img src="'+l+'" alt="JupyterLab S3 browser" loading="lazy"></p><p>The extension lets you browse buckets, upload and download files, copy S3 paths, and generate snippets for loading data with common Python libraries. The required S3 endpoint and credentials are provided through the workspace configuration, so users normally do not need to configure access manually.</p><p>For terminal, Python, and external-client access to object storage, see <a href="./../platform/object_storage.html">Object Storage</a>.</p><p>Some workflows need custom container images, for example pipeline components, KServe predictors, custom model servers, or agent runtimes. For the shared image-building workflow and limitations, see <a href="./#building-container-images">Building Container Images</a>.</p><h2 id="when-to-move-beyond-jupyterlab" tabindex="-1">When to Move Beyond JupyterLab <a class="header-anchor" href="#when-to-move-beyond-jupyterlab" aria-label="Permalink to &quot;When to Move Beyond JupyterLab&quot;">​</a></h2><p>JupyterLab is best for interactive development and inspection. Move the workload into a production-oriented runtime once the work becomes repeatable:</p><ul><li>use Kubeflow Pipelines for scheduled or reproducible workflows;</li><li>use MLflow for experiment tracking and model registry workflows;</li><li>use model serving for inference endpoints;</li><li>use AgentOps components for MCP servers, agents, and sandboxed execution.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./">Using Labs</a></li><li><a href="./custom_notebooks.html">Custom Notebooks</a></li><li><a href="https://docs.prokube.ai/latest/" target="_blank" rel="noreferrer">Existing documentation</a></li><li><a href="./../mlops/pipelines.html">Pipelines</a></li></ul>',34)])])}const y=o(d,[["render",p]]);export{f as __pageData,y as default};
